def binary_search_standard(arr, target):
    """
    Standart ikili arama: Hedefi bulan herhangi bir indeksi döndürür.
    Bulamazsa -1 döndürür.
    """
    left, right = 0, len(arr) - 1
    while left <= right:
        mid = left + (right - left) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            left = mid + 1
        else:
            right = mid - 1
    return -1

def binary_search_first_occurrence(arr, target):
    """
    Hedefin ilk geçtiği indeksi döndürür.
    Bulamazsa -1 döndürür.
    """
    left, right = 0, len(arr) - 1
    ans = -1
    while left <= right:
        mid = left + (right - left) // 2
        if arr[mid] == target:
            ans = mid
            right = mid - 1  # Daha erken bir tane bulmaya çalış
        elif arr[mid] < target:
            left = mid + 1
        else:
            right = mid - 1
    return ans

def binary_search_last_occurrence(arr, target):
    """
    Hedefin son geçtiği indeksi döndürür.
    Bulamazsa -1 döndürür.
    """
    left, right = 0, len(arr) - 1
    ans = -1
    while left <= right:
        mid = left + (right - left) // 2
        if arr[mid] == target:
            ans = mid
            left = mid + 1  # Daha geç bir tane bulmaya çalış
        elif arr[mid] < target:
            left = mid + 1
        else:
            right = mid - 1
    return ans

def binary_search_lower_bound(arr, target):
    """
    Hedefe eşit veya hedeften büyük ilk elemanın indeksini döndürür.
    Tüm elemanlar hedeften küçükse len(arr) döndürür.
    (Python'daki bisect_left'e benzer)
    """
    left, right = 0, len(arr) - 1
    ans = len(arr)
    while left <= right:
        mid = left + (right - left) // 2
        if arr[mid] >= target:
            ans = mid
            right = mid - 1
        else:
            left = mid + 1
    return ans

def binary_search_upper_bound(arr, target):
    """
    Hedeften kesinlikle büyük ilk elemanın indeksini döndürür.
    Tüm elemanlar hedefe eşit veya hedeften küçükse len(arr) döndürür.
    (Python'daki bisect_right'a benzer)
    """
    left, right = 0, len(arr) - 1
    ans = len(arr)
    while left <= right:
        mid = left + (right - left) // 2
        if arr[mid] > target:
            ans = mid
            right = mid - 1
        else:  # arr[mid] <= target
            left = mid + 1
    return ans

def binary_search_recursive(arr, target, left=0, right=None):
    """
    Standart ikili aramanın özyinelemeli (recursive) versiyonu.
    Hedefi bulan herhangi bir indeksi döndürür.
    Bulamazsa -1 döndürür.
    """
    if right is None:
        right = len(arr) - 1

    if left > right:
        return -1

    mid = left + (right - left) // 2

    if arr[mid] == target:
        return mid
    elif arr[mid] < target:
        return binary_search_recursive(arr, target, mid + 1, right)
    else:
        return binary_search_recursive(arr, target, left, mid - 1)
